"use client";

import type { StyleXStyles } from "@stylexjs/stylex";
import { useMemo } from "react";

import { cx, x } from "@/lib/utils";

import { Label } from "../label/label";
import { Separator } from "../separator/separator";
import { styles } from "./field.stylex";

type FieldOrientation = "vertical" | "horizontal" | "responsive";

const orientationStyles: Record<FieldOrientation, StyleXStyles> = {
  horizontal: styles.horizontal,
  responsive: styles.responsive,
  vertical: styles.vertical,
};

const FieldSet = ({
  className,
  style,
  ...props
}: React.ComponentProps<"fieldset">) => {
  const p = x(styles.set);
  return (
    <fieldset
      className={cx(p.className, className)}
      data-slot="field-set"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const FieldLegend = ({
  className,
  style,
  variant = "legend",
  ...props
}: React.ComponentProps<"legend"> & { variant?: "legend" | "label" }) => {
  const p = x(
    styles.legend,
    variant === "label" ? styles.legendLabel : styles.legendLegend
  );
  return (
    <legend
      className={cx(p.className, className)}
      data-slot="field-legend"
      data-variant={variant}
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const FieldGroup = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = x(styles.group);
  return (
    <div
      className={cx(p.className, className)}
      data-slot="field-group"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const Field = ({
  className,
  style,
  orientation = "vertical",
  ...props
}: React.ComponentProps<"div"> & { orientation?: FieldOrientation }) => {
  const p = x(styles.fieldBase, orientationStyles[orientation]);
  return (
    <div
      className={cx(p.className, className)}
      data-orientation={orientation}
      data-slot="field"
      role="group"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const FieldContent = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = x(styles.content);
  return (
    <div
      className={cx(p.className, className)}
      data-slot="field-content"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const FieldLabel = ({
  className,
  ...props
}: React.ComponentProps<typeof Label>) => {
  const p = x(styles.label);
  return (
    <Label
      className={cx(p.className, className)}
      data-slot="field-label"
      {...props}
    />
  );
};

const FieldTitle = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = x(styles.title);
  return (
    <div
      className={cx(p.className, className)}
      data-slot="field-label"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const FieldDescription = ({
  className,
  style,
  ...props
}: React.ComponentProps<"p">) => {
  const p = x(styles.description);
  return (
    <p
      className={cx(p.className, className)}
      data-slot="field-description"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const FieldSeparator = ({
  children,
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = x(styles.separator);
  const line = x(styles.separatorLine);
  const content = x(styles.separatorContent);
  return (
    <div
      className={cx(p.className, className)}
      data-content={Boolean(children)}
      data-slot="field-separator"
      style={{ ...p.style, ...style }}
      {...props}
    >
      <Separator className={line.className} style={line.style} />
      {children ? (
        <span
          className={content.className}
          data-slot="field-separator-content"
          style={content.style}
        >
          {children}
        </span>
      ) : null}
    </div>
  );
};

const FieldError = ({
  className,
  style,
  children,
  errors,
  ...props
}: React.ComponentProps<"div"> & {
  errors?: ({ message?: string } | undefined)[];
}) => {
  const content = useMemo(() => {
    if (children) {
      return children;
    }
    if (!errors?.length) {
      return null;
    }
    const uniqueErrors = [
      ...new Map(errors.map((error) => [error?.message, error])).values(),
    ];
    if (uniqueErrors.length === 1) {
      return uniqueErrors[0]?.message;
    }
    return (
      <ul style={{ display: "flex", flexDirection: "column", gap: "0.25rem" }}>
        {uniqueErrors.map((error) =>
          error?.message ? <li key={error.message}>{error.message}</li> : null
        )}
      </ul>
    );
  }, [children, errors]);

  if (!content) {
    return null;
  }

  const p = x(styles.error);
  return (
    <div
      className={cx(p.className, className)}
      data-slot="field-error"
      role="alert"
      style={{ ...p.style, ...style }}
      {...props}
    >
      {content}
    </div>
  );
};

export {
  Field,
  FieldLabel,
  FieldDescription,
  FieldError,
  FieldGroup,
  FieldLegend,
  FieldSeparator,
  FieldSet,
  FieldContent,
  FieldTitle,
};

import * as stylex from "@stylexjs/stylex";

import { colors } from "../tokens.stylex";

export const styles = stylex.create({
  content: {
    display: "flex",
    flex: 1,
    flexDirection: "column",
    gap: "0.375rem",
    lineHeight: 1.375,
  },
  description: {
    color: colors.mutedForeground,
    fontSize: "0.875rem",
    fontWeight: 400,
    lineHeight: 1.5,
  },
  error: {
    color: colors.destructive,
    fontSize: "0.875rem",
    fontWeight: 400,
  },
  fieldBase: {
    display: "flex",
    gap: "0.75rem",
    width: "100%",
  },
  group: {
    display: "flex",
    flexDirection: "column",
    gap: "1.75rem",
    width: "100%",
  },
  horizontal: {
    alignItems: "center",
    flexDirection: "row",
  },
  label: {
    alignItems: "center",
    display: "flex",
    gap: "0.5rem",
    lineHeight: 1.375,
    width: "fit-content",
  },
  legend: {
    fontWeight: 500,
    marginBottom: "0.75rem",
  },
  legendLabel: {
    fontSize: "0.875rem",
  },
  legendLegend: {
    fontSize: "1rem",
  },
  responsive: {
    alignItems: { "@media (min-width: 768px)": "center", default: null },
    flexDirection: { "@media (min-width: 768px)": "row", default: "column" },
  },
  separator: {
    alignItems: "center",
    display: "flex",
    fontSize: "0.875rem",
    height: "1.25rem",
    justifyContent: "center",
    marginBlock: "-0.5rem",
    position: "relative",
  },
  separatorContent: {
    backgroundColor: colors.background,
    color: colors.mutedForeground,
    display: "block",
    marginInline: "auto",
    paddingInline: "0.5rem",
    position: "relative",
    width: "fit-content",
  },
  separatorLine: {
    insetInline: 0,
    position: "absolute",
    top: "50%",
  },
  set: {
    display: "flex",
    flexDirection: "column",
    gap: "1.5rem",
  },
  title: {
    alignItems: "center",
    display: "flex",
    fontSize: "0.875rem",
    fontWeight: 500,
    gap: "0.5rem",
    lineHeight: 1.375,
    width: "fit-content",
  },
  vertical: {
    flexDirection: "column",
  },
});
